create table if not exists public.agent_mission_states(id uuid primary key default gen_random_uuid(),mission_id uuid not null references public.missions(id) on delete cascade,user_id uuid not null references auth.users(id) on delete cascade,workspace_id uuid,structured_state jsonb not null default '{}'::jsonb,execution_state text not null default 'PLANNING',version integer not null default 1,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(mission_id,version));
create table if not exists public.agent_tool_audit(id uuid primary key default gen_random_uuid(),mission_id uuid not null references public.missions(id) on delete cascade,user_id uuid not null references auth.users(id) on delete cascade,tool_id text not null,status text not null,risk_class text not null,approval_request_id uuid references public.approval_requests(id),sanitized_metadata jsonb not null default '{}'::jsonb,created_at timestamptz not null default now());
create table if not exists public.agent_usage_windows(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,workspace_id uuid,window_started_at timestamptz not null,request_count integer not null default 0,input_tokens integer not null default 0,output_tokens integer not null default 0,tool_calls integer not null default 0,updated_at timestamptz not null default now(),unique(user_id,workspace_id,window_started_at));
alter table public.agent_mission_states enable row level security;alter table public.agent_tool_audit enable row level security;alter table public.agent_usage_windows enable row level security;
create policy agent_state_owner_read on public.agent_mission_states for select using(auth.uid()=user_id);create policy agent_audit_owner_read on public.agent_tool_audit for select using(auth.uid()=user_id);create policy agent_usage_owner_read on public.agent_usage_windows for select using(auth.uid()=user_id);
revoke insert,update,delete on public.agent_mission_states from authenticated;revoke insert,update,delete on public.agent_tool_audit from authenticated;revoke insert,update,delete on public.agent_usage_windows from authenticated;
